-- ── Revive Adserver ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Revive Adserver is a free, open-source ad-serving platform descended from OpenX Source and phpAdsNew that lets publishers and ad networks manage and deliver banner, text, and video ads from a self-hosted server.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (GPL license) for self-hosted use; an optional hosted edition is available from third-party providers for a monthly fee.$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted edition from around $10/month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Open-source community project (no fixed employee count); currently maintained by Aqua Platform$q$, company_size),
  headquarters = COALESCE($q$No corporate headquarters - open-source project; originally developed under OpenX Technologies, now maintained by Aqua Platform$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$plus community-contributed translations into multiple other languages$q$]::text[],
  seo_title = COALESCE($q$Revive Adserver Review 2026: Free Open-Source Ad Server Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Revive Adserver, the free open-source ad server descended from OpenX. See features, self-hosting requirements, and hosted pricing for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Revive Adserver is a free, open-source ad-serving platform licensed under the GNU General Public License, used by publishers, ad networks, and agencies to manage and deliver banner, text, rich media, and video ad campaigns from a self-hosted server. Its lineage traces back to the phpAdsNew project led by Wim Godden starting around 2000 to 2001, which evolved into Openads and then, in 2007, into OpenX Source. In September 2013, the OpenX Source codebase was acquired and rebranded as Revive Adserver, with its first release under the new name being version 3.0.0. Intellectual property rights passed to Revive Software and Services in 2015, and stewardship of the project was transferred again in 2024 to Aqua Platform, which now maintains the software and offers an optional hosted edition. As of mid-2026 the current stable self-hosted release is version 6.0.8. Because it is a community open-source project rather than a conventional company, Revive Adserver has no single corporate headquarters or fixed employee count; development is driven by a mix of paid maintainers and community contributors listed on its GitHub repository, and the project accepts donations and sponsorships through Patreon from businesses that generate revenue using the software. Functionally, Revive Adserver provides zone-based ad targeting by browser, domain, and language; standard banner rotation and click and impression tracking; frequency/ad capping to limit how often a visitor sees the same creative; and, since the introduction of a plugin architecture in version 2.8 of the OpenX-era codebase, an extensible system for adding custom functionality. It also offers a REST API for programmatic campaign and inventory management. The self-hosted, downloadable edition is completely free to use on a publisher's or agency's own infrastructure, with no licensing or per-impression fees, making it a popular choice for independent publishers and smaller ad networks that want to avoid vendor lock-in and retain full control of their ad-serving data. For organizations that do not want to manage their own servers, Aqua Platform offers a hosted edition of Revive Adserver starting at approximately $10 per month, which removes the need for self-managed infrastructure while still running the same open-source codebase. Because it is open source, Revive Adserver does not have traditional SaaS-style pricing tiers, customer support contracts, or a sales organization in the way commercial ad servers do; support instead comes primarily from community forums, documentation, and GitHub, with the hosted edition offering more direct technical assistance.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e449918-7518-479f-8208-8ee3735b2652';

