-- ── Revolut Business ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Revolut Business is the business banking and spend-management arm of London-based fintech Revolut, offering multi-currency accounts, corporate cards, and payment tools for companies of all sizes.$q$, short_description),
  pricing_model = COALESCE($q$Tiered monthly subscription (Basic, Grow, Scale) plus custom Enterprise pricing; annual billing offers a discount over monthly billing.$q$, pricing_model),
  starting_price = COALESCE($q$Free (Basic plan); paid plans from $30/month (Grow)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$10,000+ employees (Revolut Group)$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and multiple other languages supported across Revolut's global app$q$]::text[],
  seo_title = COALESCE($q$Revolut Business Pricing and Features 2026: Full Review$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Revolut Business pricing plans, multi-currency features, and corporate card benefits for 2026 in this detailed review.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Revolut Business is the business banking and spend-management product line of Revolut, the London-headquartered fintech company founded in July 2015 by Nik Storonskiy and Vlad Yatsenko. While the wider Revolut group has grown into a large financial technology company with tens of thousands of employees globally and a reported valuation of around $75 billion as of a November 2025 share sale, and serves more than 70 million customers worldwide, Revolut Business specifically targets companies ranging from small startups to larger enterprises that need multi-currency accounts and modern payment tools without relying solely on a traditional bank. In the United States, Revolut Business is sold across four tiers: Basic, which is free and includes a multi-currency account plus a small number of free transfers per month; Grow, priced at $30 per month, which adds 100 free local transfers, 5 free international payments, up to $10,000 in fee-free FX exchange, bulk payments, and a complimentary metal card; Scale, priced at $119 per month, which raises those allowances to 1,000 free local transfers, 25 free international payments, and $80,000 in fee-free exchange while adding API access and granular team permissions; and Enterprise, which is custom-priced and includes tailored allowances, a dedicated account manager, and priority support with defined response times. Annual billing can save up to 22% compared with paying monthly. Core features across the product include the ability to hold, send, and receive 25 or more currencies at or near the interbank exchange rate, physical and virtual corporate cards with real-time spend controls, bulk payment tools capable of paying up to 1,000 suppliers or staff members at once, and accounting integrations with platforms such as Xero and QuickBooks. Higher tiers unlock API access for custom integrations and more granular role-based permissions for finance teams. Because Revolut operates primarily as an e-money institution rather than a full bank in many markets, deposit protections and regulatory treatment can differ from a traditional bank account depending on the customer's country, and feature availability, plan names, and pricing vary somewhat by region. Revolut Business is most commonly used by e-commerce companies paying international suppliers, startups that need multi-currency accounts from day one, and finance teams that want bulk payroll or vendor payment tools without juggling multiple banking relationships.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a1159d03-001f-4c6e-ae84-122c6665f96f';

