-- ── RhodeCode ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RhodeCode is a Berlin-based enterprise source code management platform that unifies Git, Mercurial, and Subversion repositories with code review, permissions, and integrations, available as a free open-source Community Edition or paid Enterprise and Cloud editions.$q$, short_description),
  pricing_model = COALESCE($q$Free open-source Community Edition; paid Enterprise Edition licensed per user per year; paid Cloud edition billed per user per month, each with a 10-user minimum.$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Enterprise from $75/user/year; Cloud from $8/user/month$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Small, privately held company (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany (with an additional office in Palo Alto, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$RhodeCode Review 2026: Pricing and Features for Git, SVN, Mercurial$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare RhodeCode Community, Enterprise, and Cloud pricing and features for managing Git, Mercurial, and Subversion repositories in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RhodeCode is an enterprise source code management platform originally started in 2010 by Marcin Kuzminski, with the company formally incorporated in July 2013 alongside co-founder Sebastian Kreutzberger. The company is headquartered in Berlin, Germany, and also maintains an office in Palo Alto, California; it is a small, privately held company that has not publicly disclosed a precise employee count. RhodeCode's core product distinguishes itself from single-VCS platforms like GitHub or GitLab by unifying three version control systems, Git, Mercurial, and Subversion, under one centralized management layer, letting organizations apply common authentication, permissions, and code review workflows regardless of which VCS a given team or repository uses. This makes it particularly relevant to larger enterprises, regulated industries, and organizations with legacy Subversion or Mercurial repositories that still need centralized governance alongside newer Git-based projects. RhodeCode is offered in three editions. RhodeCode Community Edition (CE) is free and open source, supports an unlimited number of users and repositories, and can be deployed entirely on-premises, including fine-grained permission controls, code review tools, full-text code search, APIs for custom tool integration, and basic LDAP/Active Directory authentication, backed by community support. RhodeCode Enterprise Edition (EE) is the paid, for-fee tier built on top of CE, priced at $75 per user per year with a minimum purchase of 10 users (sold in 10-user packs, with volume and multi-year discounts available); it adds features such as technical support with a service-level agreement, built-in code chat and smart reviewer assignment for instant code reviews, scalable code search across all repositories, high-availability multi-node deployment architecture, predefined integrations with tools like JIRA, Jenkins, Bamboo, and Slack, and unified enterprise authentication covering LDAP with groups, SAML, Active Directory, CAS, Google, OAuth, and two-factor authentication. A newer RhodeCode Cloud offering starts at $8 per user per month, also with a 10-user minimum, and includes all Enterprise Edition features on managed infrastructure with a dedicated domain and enterprise-grade SSL, unlimited traffic, disk space, and repository size, dedicated isolated hardware, geo-located instances across the US, Asia, and Europe, daily backups, and built-in error and performance monitoring, billed as a cancel-anytime monthly subscription. RhodeCode targets software developers, project managers, and DevOps engineers at organizations that need centralized, compliant control over multiple version control systems rather than a single-VCS developer platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '85550e75-0afc-4140-81a3-4e711ba76ca4';

