-- ── Richpanel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Richpanel is a San Jose-based AI-powered customer service and helpdesk platform built specifically for e-commerce brands, unifying email, chat, social, and self-service support in one inbox.$q$, short_description),
  pricing_model = COALESCE($q$Per-agent monthly subscription billed annually (Pro, Pro Max), custom Enterprise pricing, plus an optional AI agent add-on and a separate self-service portal add-on.$q$, pricing_model),
  starting_price = COALESCE($q$$59/agent/month billed annually (Pro plan)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small-to-midsize private company (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Richpanel Review 2026: Pricing and Features for Ecommerce Support$q$, seo_title),
  seo_meta_description = COALESCE($q$See Richpanel pricing plans, AI agent add-on costs, and helpdesk features for 2026 e-commerce customer support teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Richpanel is a customer service software company founded in 2019 and headquartered in San Jose, California, that builds AI-powered helpdesk infrastructure specifically for e-commerce and direct-to-consumer brands rather than general-purpose businesses. The platform combines three layers in one product: multi-channel support infrastructure that centralizes email, live chat, and social media conversations into a single agent inbox; AI-powered automation, including an AI customer service agent that can resolve tickets on its own; and self-service components that let shoppers manage their own orders, returns, and exchanges without needing to contact an agent. On its help desk side, Richpanel sells two named self-serve plans plus a custom Enterprise tier: Pro, at $59 per agent per month when billed annually (equivalent to $708 per year), covers up to three seats and includes email, live chat, and social channel support along with basic reporting, automation rules, and AI features included at no extra cost; Pro Max, at $89 per agent per month billed annually ($1,068 per year), adds SMS and phone support, unlimited automations and campaigns, support for multiple brands and languages, and more advanced reporting covering revenue impact and customer satisfaction; and Enterprise, which requires a minimum of 10 agents, is custom priced, and includes white-glove onboarding, a campaign manager, and custom integrations. Separately, Richpanel also sells a standalone AI agent product, where a single AI agent costs $500 per month plus an additional $100 per seat for the helpdesk the human team works in, reflecting a per-store rather than strictly per-agent pricing philosophy for its AI offering. A self-service portal add-on, covering order management, returns processing, a branded help center, and custom automation flows, is available separately for roughly $99 to $500 per month depending on scale. All plans include 24/5 customer support, white-glove migration assistance from other helpdesk tools, the ability to remove Richpanel branding, and a contract buyout program for customers switching from competitors; Richpanel also advertises a guarantee of at least 30% savings versus platforms like Zendesk or Gorgias along with a 30% reduction in ticket volume within 60 days, or a refund. Richpanel integrates natively with Shopify and other e-commerce platforms, making it best suited to online retailers that want AI-driven automation and self-service tightly coupled with their storefront rather than a horizontal, industry-agnostic support tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb';

