-- ── RingCentral ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RingCentral is a publicly traded, Belmont, California-based provider of AI-powered cloud business communications, offering phone, messaging, video meetings, and contact center software under its RingEX (formerly RingCentral MVP) platform.$q$, short_description),
  pricing_model = COALESCE($q$Per-user monthly subscription tiers (Core, Advanced, Ultra), with lower per-user rates for annual billing; Contact Center is sold as a separate add-on.$q$, pricing_model),
  starting_price = COALESCE($q$From $20/user/month billed annually (Core plan); $30/user/month billed monthly$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE($q$Approximately 4,000-7,000 employees$q$, company_size),
  headquarters = COALESCE($q$Belmont, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and multiple other languages supported for its global customer base$q$]::text[],
  seo_title = COALESCE($q$RingCentral Pricing 2026: Plans, Features and Full Review$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare RingCentral RingEX pricing tiers, features, and pros and cons for 2026 cloud business phone and communications.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RingCentral, Inc. is a publicly traded (NYSE: RNG) provider of cloud-based business communications founded in 1999 and headquartered in Belmont, California. The company reports trailing twelve-month revenue of roughly $2.5 billion and employee counts that vary by source from around 4,260 to over 7,000, reflecting its growth from an early VoIP provider into one of the larger unified-communications-as-a-service (UCaaS) vendors globally. Its flagship product, historically branded RingCentral MVP (Message, Video, Phone) and now marketed as RingEX, bundles a cloud-hosted business phone system, team messaging, video meetings, and SMS/MMS texting into a single per-user subscription, with a separate Contact Center product available as an add-on for customer service and call center use cases. RingEX is sold in three tiers. The Core plan starts at $20 per user per month when billed annually (or $30 per user per month billed monthly) and includes unlimited calling within the US and Canada, voicemail-to-text, call queues, an auto-attendant for automated call routing, video meetings for up to 100 participants, and 25 SMS messages per user per month, though it lacks automatic call recording. The Advanced plan runs $25 per user per month annually (or $35 monthly) and adds features such as automatic call recording and higher usage limits on top of everything in Core. The Ultra plan, at $35 per user per month annually (or $45 monthly), is the top tier and includes everything in Advanced plus expanded video meeting capacity of up to 200 participants, unlimited storage, and device analytics. Across all tiers, RingCentral emphasizes AI-powered features branded as RingCentral AI, including call summaries, transcription, and assistant tools, and the platform integrates with more than 300 third-party applications including Microsoft 365, Google Workspace, and Salesforce. Because RingCentral's list pricing does not always include compliance fees, additional phone numbers, or usage overages, actual invoiced costs commonly run 20-35% above the advertised per-user rate according to several third-party pricing analyses. RingCentral is used across organizations of all sizes, from small businesses replacing a legacy phone system to large enterprises consolidating multiple communication vendors into a single UCaaS platform, and its Contact Center add-on extends the core phone and messaging platform into full omnichannel customer service deployments for larger call center operations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '92a082b4-89b7-491c-a783-39088d0397e1';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '92a082b4-89b7-491c-a783-39088d0397e1' AND logo IS NULL AND website IS NOT NULL;

