-- ── RingCentral Video ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RingCentral Video (formerly RingCentral Meetings) is RingCentral Inc.'s dedicated video conferencing product, offering a free tier for meetings up to 100 participants and a paid Pro+ tier for larger, longer meetings with more storage and security.$q$, short_description),
  pricing_model = COALESCE($q$Freemium: a free Video Pro tier plus a paid Video Pro+ per-user monthly subscription; larger meeting capacity is also bundled into RingEX phone plans.$q$, pricing_model),
  starting_price = COALESCE($q$Free (Video Pro plan); Video Pro+ from $10/user/month billed annually$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE($q$Approximately 4,000-7,000 employees (RingCentral Inc.)$q$, company_size),
  headquarters = COALESCE($q$Belmont, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and multiple other languages supported for its global customer base$q$]::text[],
  seo_title = COALESCE($q$RingCentral Video Pricing 2026: Free and Pro+ Plans Compared$q$, seo_title),
  seo_meta_description = COALESCE($q$See RingCentral Video's free and paid pricing, participant limits, and features for 2026, including how it compares to RingEX bundles.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RingCentral Video is the dedicated video conferencing product from RingCentral, Inc., the publicly traded (NYSE: RNG) communications company founded in 1999 and headquartered in Belmont, California. The video product has evolved over time from what was originally branded RingCentral Meetings into today's RingCentral Video, and it is offered both as a standalone freemium product and as a bundled component of RingCentral's broader RingEX phone and messaging plans. On the free side, RingCentral Video Pro allows unlimited meetings for up to 100 participants, though each individual meeting is capped at 50 minutes, making it comparable in structure to free tiers offered by other major video conferencing vendors. For teams that need longer or larger meetings, RingCentral Video Pro+ is priced at $10 per user per month when billed annually and removes the 50-minute cap, supporting meetings of up to 24 hours in length, while also raising the participant capacity to up to 200 people. Video Pro+ additionally unlocks cloud recording for saving and sharing meetings, end-to-end encryption for more security-conscious teams, and expanded cloud storage. Beyond the standalone video product, RingCentral bundles expanded video meeting capacity directly into its RingEX unified communications plans: customers on a paid RingEX subscription automatically receive unlimited 24-hour video meetings for up to 200 participants as part of their phone plan, meaning many organizations experience RingCentral's video capabilities through their broader communications subscription rather than purchasing Video Pro+ as a separate line item. Common features across the free and paid video tiers include screen sharing, in-meeting chat, calendar integrations with tools like Google Calendar and Outlook for scheduling, and AI-powered meeting tools such as automatically generated notes, transcription, and summaries, consistent with RingCentral's broader investment in AI features across its communications portfolio. Because RingCentral Video shares its underlying infrastructure and company with RingCentral's core RingEX phone platform, its company-level facts, including the 1999 founding date, Belmont, California headquarters, and an employee count reported between roughly 4,260 and over 7,000 depending on the source, are identical to those of the parent RingCentral, Inc. business, even though the video product itself is marketed, priced, and evaluated as its own distinct offering aimed at teams that primarily need video meetings rather than a full phone system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '88db22aa-79b8-45ed-b2f4-437c05395830';

