INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Review Generation$q$, $q$Automated SMS and email review requests sent to customers after an interaction to drive new reviews.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$AI Review Response$q$, $q$AI-assisted suggestions and templates to help teams reply to reviews faster and more consistently.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Sentiment and Keyword Alerts$q$, $q$Real-time alerts when new reviews mention specific keywords or shift in sentiment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Competitor Insights$q$, $q$Benchmarks review volume and sentiment against named competitors on the Essential plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Review Widgets$q$, $q$Embeddable review carousel widgets for showcasing reviews on a company website.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Multi-Location Reporting$q$, $q$Dashboards and analytics for comparing reputation performance across many locations or franchises.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Local Listings Management$q$, $q$Optional add-on for managing and correcting business listings across online directories.$q$, 7);
