INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Pricing is not fully transparent and often requires a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Per-location pricing can add up for large franchise networks$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Competitor insights are locked behind the Essential tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Learning curve for the full analytics suite$q$, 3);
