INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Add-on modules are all separately priced$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Does ReviewTrackers offer a free trial?$q$, $q$Yes, ReviewTrackers offers a free trial so prospective customers can evaluate the platform before subscribing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$What review sites does ReviewTrackers monitor?$q$, $q$It aggregates reviews from over 100 sources, including major platforms like Google, Facebook, and Yelp, plus industry-specific review sites.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Who owns ReviewTrackers?$q$, $q$ReviewTrackers was acquired by customer experience management company InMoment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Is ReviewTrackers priced per user or per location?$q$, $q$Pricing is based on business location, with unlimited users included on the platform tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$What is the difference between the Starter and Essential plans?$q$, $q$Essential includes everything in Starter plus competitor insights, experience analysis, and a carousel review widget.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Does ReviewTrackers support SMS review requests?$q$, $q$Yes, the platform supports automated review solicitation via both SMS and email.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Is there an API or raw data option?$q$, $q$The Data Only plan provides aggregated review data for use in a company's own systems rather than the full platform.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Does ReviewTrackers offer add-ons beyond review management?$q$, $q$Yes, optional add-ons include local listings management, local search rank tracking, managed services, and white-label reporting.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Multi-location retail and franchise brands$q$, $q$Centralizes review monitoring and response across dozens or hundreds of storefronts from one dashboard.$q$, $q$Retail chains and franchise operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Healthcare and dental practice groups$q$, $q$Helps practice groups track patient sentiment and respond to reviews consistently across locations.$q$, $q$Multi-location healthcare and dental organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Automotive dealership groups$q$, $q$Benchmarks dealership review performance against competitors and automates review generation after service visits.$q$, $q$Auto dealership groups and service centers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Data Only$q$, $q$Custom quote$q$, $q$monthly (custom)$q$, NULL, $q$["Aggregated review data from 100+ sources","Raw data feed for use in your own platform or BI tools","Suited for organizations that only need data, not the full dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Starter$q$, $q$From approximately $49-89 per location per month (custom quote)$q$, $q$monthly, billed annually$q$, NULL, $q$["Unlimited users","Dashboards and analytics","Review solicitation via email and SMS","AI-assisted review responses","Keyword and sentiment alerts","Review response management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Essential$q$, $q$Custom quote$q$, $q$monthly, billed annually$q$, NULL, $q$["Everything in Starter","Experience analysis","Competitor insights","Carousel-only amplify review widget"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$Add-On Modules$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["Local listings management","Local search rank tracking","Managed services","White-label reporting","Employer brand package","App store review package"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ReviewTrackers was founded in 2012 and is headquartered in Chicago, Illinois. The company builds reputation management software for multi-location businesses, aggregating reviews from more than 100 sources into a single platform. It was later acquired by customer experience company InMoment, and today serves industries such as retail, healthcare, automotive, and franchise brands that need to monitor and respond to reviews across many locations at once.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines review monitoring, automated SMS and email review generation, AI-assisted review responses, and keyword or sentiment alerts in a single dashboard. Higher-tier customers also get competitor benchmarking, experience analysis, and embeddable review widgets, while add-on modules extend the platform into local listings management, local search rank tracking, and white-label reporting for agencies and enterprise brands.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39c68560-090d-4a39-b278-5e450024c11c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ReviewTrackers prices per business location across three tiers: Data Only, Starter, and Essential, with unlimited users included on the platform plans. Third-party pricing trackers report starting prices in the roughly $49 to $89 per location per month range when billed annually, but exact figures for most tiers, and all add-on modules, require a custom quote directly from ReviewTrackers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Self-Hosted Ad Serving$q$, $q$Deploy the full ad server on your own infrastructure at no licensing cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Zone-Based Targeting$q$, $q$Target ad delivery by browser, domain, language, and other visitor attributes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Plugin Architecture$q$, $q$Extend core functionality with plugins, a system introduced in the OpenX-era codebase.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Multi-Format Ad Support$q$, $q$Serve banner, text, rich media, and video ad formats from one system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Click and Impression Tracking$q$, $q$Built-in statistics and tracking system for measuring campaign performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Frequency Capping$q$, $q$Limit how often the same visitor sees a given ad.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$REST API$q$, $q$Programmatically manage campaigns, zones, and inventory via the Revive Adserver REST API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$GPL Open-Source License$q$, $q$Full access to the source code with no vendor lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Completely free to self-host under the GPL license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Long track record with roots going back to the early 2000s$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Active open-source community and GitHub contributor base$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Full control and customization of source code and data$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$REST API available for automation and integrations$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$No per-impression licensing fees$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Requires self-hosting and ongoing server maintenance for the free edition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Admin interface feels dated compared to modern SaaS ad servers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Technical setup (PHP/MySQL environment) is required$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Limited official support without opting into the paid hosted plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Fewer built-in programmatic/RTB integrations than commercial ad servers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Documentation can be sparse for some newer features$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Is Revive Adserver really free?$q$, $q$Yes, the self-hosted, downloadable edition is free and open source under the GPL license, with no licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$What license does Revive Adserver use?$q$, $q$It is released under the GNU General Public License (GPL).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Who maintains Revive Adserver today?$q$, $q$The project is currently maintained by Aqua Platform, which took over stewardship in 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$What was Revive Adserver called before?$q$, $q$It was formerly known as OpenX Source, and before that Openads and phpAdsNew.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Does Revive Adserver support video ads?$q$, $q$Yes, in addition to banner and text ads, it supports rich media and video ad formats.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Can I get a hosted version of Revive Adserver?$q$, $q$Yes, Aqua Platform offers a hosted edition starting at around $10 per month for users who do not want to self-host.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$What are the server requirements for self-hosting?$q$, $q$Revive Adserver runs on a standard PHP and MySQL server environment that publishers manage themselves.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Does Revive Adserver have an API?$q$, $q$Yes, it offers a REST API for programmatic campaign and inventory management.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Independent publishers self-hosting ad inventory$q$, $q$Publishers who want full control of their ad-serving data and no per-impression fees run their own Revive Adserver instance.$q$, $q$Independent website and app publishers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Ad networks needing white-label ad serving$q$, $q$Smaller ad networks use the open-source codebase as the foundation for white-labeled ad delivery to their clients.$q$, $q$Ad networks and adtech resellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Agencies managing house and affiliate campaigns$q$, $q$Agencies self-host Revive Adserver to manage house ads and affiliate campaigns across multiple client sites.$q$, $q$Digital agencies and affiliate marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Self-Hosted (Community)$q$, $q$Free$q$, $q$n/a (free, one-time download)$q$, NULL, $q$["Full open-source ad server software","Banner, text, rich media, and video ad support","GPL open-source license","Unlimited campaigns and zones on your own infrastructure","Self-hosted on your own server","Community support via forums and GitHub","Plugin architecture for extensions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$Hosted Edition$q$, $q$From approximately $10/month$q$, $q$monthly$q$, NULL, $q$["Cloud-hosted by Aqua Platform","No server maintenance required","Automatic updates","SSL included","Direct technical support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Revive Adserver is an open-source ad server whose codebase traces back to the phpAdsNew project from around 2000-2001, which became Openads and then OpenX Source by 2007. When OpenX Source was acquired and rebranded in September 2013, it became Revive Adserver, released under the GNU General Public License. Project stewardship passed to Revive Software and Services in 2015 and then to Aqua Platform in 2024, which maintains the software today and offers a paid hosted edition alongside the free self-hosted download.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform supports zone-based ad targeting, banner rotation, click and impression tracking, frequency capping, and multiple ad formats including banner, text, rich media, and video. A plugin architecture, introduced in the OpenX era, allows developers to extend core functionality, and a REST API enables programmatic management of campaigns and inventory.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The downloadable, self-hosted edition of Revive Adserver is completely free under its GPL open-source license, with no licensing or per-impression fees. Organizations that prefer not to manage their own servers can use a hosted edition offered by maintainer Aqua Platform, which starts at approximately $10 per month. The project also accepts voluntary sponsorships via Patreon from businesses earning revenue through the software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3e449918-7518-479f-8208-8ee3735b2652', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
