INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Corporate Cards$q$, $q$Physical and virtual cards with real-time spend controls for employees and teams.$q$, 1);
