INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Team Permissions$q$, $q$Granular, role-based access controls for finance and admin teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Fee-Free Transfer Allowances$q$, $q$Each plan includes a set number of free local and international transfers per month.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Accounting Integrations$q$, $q$Connects with accounting platforms such as Xero and QuickBooks.$q$, 6);
