INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Competitive interbank-rate currency exchange$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Fast, largely digital account opening process$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Wide multi-currency support (25+ currencies)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Plans scale from startups up to larger enterprises$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Strong mobile and web app experience$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Customer support experience has mixed reviews at higher volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Operates as an e-money institution in many markets rather than a full bank, so deposit protections can differ from traditional banks$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Scale plan pricing ($119/month) is a meaningful jump from Grow$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$API access is gated behind the higher-tier plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Fee-free transfer allowances can be exceeded quickly by high-volume businesses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Feature availability and pricing vary by country$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Is Revolut Business a bank?$q$, $q$In many markets Revolut operates under an e-money license rather than as a full bank, though this varies by region and has been changing as Revolut obtains banking licenses in more countries.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Which currencies does Revolut Business support?$q$, $q$It supports holding, sending, and receiving 25 or more currencies at competitive exchange rates.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Is there a free Revolut Business plan?$q$, $q$Yes, the Basic plan is free and includes a multi-currency account with a limited number of free transfers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$How does pricing compare across Revolut Business tiers?$q$, $q$In the US, plans run Basic (free), Grow ($30/month), Scale ($119/month), and custom-priced Enterprise, with increasing transfer allowances and features at each tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Does Revolut Business offer an API?$q$, $q$Yes, API access is included on the Scale and Enterprise plans for building custom integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$What is the difference between Grow and Scale?$q$, $q$Scale offers significantly higher free transfer and FX allowances plus API access and more granular team permissions than Grow.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$What accounting software does Revolut Business integrate with?$q$, $q$It integrates with accounting platforms such as Xero and QuickBooks, among others.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Can I save money by paying annually?$q$, $q$Yes, annual subscriptions can save up to 22% compared to monthly billing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$E-commerce businesses paying international suppliers$q$, $q$Uses multi-currency accounts and competitive FX rates to pay overseas suppliers without excessive conversion fees.$q$, $q$E-commerce and import/export businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Startups needing multi-currency accounts$q$, $q$Opens a business account quickly without relying on a traditional bank, supporting multiple currencies from day one.$q$, $q$Early-stage and growing startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Finance teams managing bulk payroll or vendor payments$q$, $q$Uses bulk payment tools to pay up to 1,000 suppliers or staff members in a few clicks.$q$, $q$Finance and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Basic$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Multi-currency account","A limited number of free transfers per month","Physical or virtual card","Basic expense management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Grow$q$, $q$$30/month$q$, $q$monthly (annual billing available at a discount)$q$, NULL, $q$["100 free local transfers","5 free international payments","Up to $10,000 in fee-free FX exchange","Bulk payments","Complimentary metal card"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Scale$q$, $q$$119/month$q$, $q$monthly (annual billing available at a discount)$q$, NULL, $q$["1,000 free local transfers","25 free international payments","Up to $80,000 in fee-free FX exchange","API access","Granular team permissions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Tailored transfer and FX allowances","Dedicated account manager","Priority support with defined response times","Custom approval workflows"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Revolut was founded in July 2015 by Nik Storonskiy and Vlad Yatsenko and is headquartered in London, United Kingdom. Revolut Business is the company's dedicated banking and spend-management product for companies, built on top of the same multi-currency infrastructure that powers Revolut's consumer app. The wider Revolut group has grown into one of the largest fintechs globally, with a valuation of around $75 billion reported in late 2025 and tens of thousands of employees worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Revolut Business lets companies hold, send, and receive 25-plus currencies at competitive exchange rates, issue physical and virtual corporate cards with real-time spend controls, and make bulk payments to up to 1,000 payees at once. Higher-tier plans add API access for custom integrations and granular, role-based team permissions for finance teams, along with accounting software integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1159d03-001f-4c6e-ae84-122c6665f96f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$In the US, Revolut Business is sold across four plans: Basic (free), Grow ($30/month), Scale ($119/month), and a custom-priced Enterprise tier. Each paid tier increases the number of free local and international transfers and the amount of fee-free currency exchange included, and annual billing offers savings of up to 22% versus paying monthly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Business Checking$q$, $q$No monthly fees, no minimum balance requirement, and no ACH or wire transfer fees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Corporate Cards$q$, $q$Physical and virtual cards with up to 1.5% cash back and no annual or per-card fees.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Accounts Payable Automation$q$, $q$Bill pay and invoice approval workflows built into the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Expense Management$q$, $q$Real-time spend controls and expense categorization for employee cards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Rho Treasury$q$, $q$SEC-registered investment advisory offering higher-yield cash management with a tiered management fee.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$FDIC Sweep Coverage$q$, $q$Extends FDIC insurance protection on deposits up to $75 million through a partner bank sweep network.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Customizable Approval Workflows$q$, $q$Multi-level spend and payment approval policies for finance teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$24/7 Customer Support$q$, $q$Round-the-clock live support included with the platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$No monthly subscription or per-user fees for core banking and cards$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Corporate cards earn up to 1.5% cash back with no annual fee$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$High FDIC sweep coverage of up to $75 million via Rho Treasury$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Combines banking, AP automation, and expense management in one platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Backed by well-known venture investors with roughly $235 million raised$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$24/7 customer support included$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Rho Treasury charges an AUM-based management fee for higher-yield cash management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Not a chartered bank itself; relies on partner bank infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$No lending, credit card, or investment products offered$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Detailed company headcount is not well publicized$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Advanced automation features are reserved for the top Scale tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Primarily built for US-based companies$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Is Rho a bank?$q$, $q$Rho is a fintech company; its banking services, such as FDIC insurance, are provided through partner banks rather than Rho itself holding a bank charter.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Does Rho charge monthly fees?$q$, $q$No, Rho does not charge monthly subscription fees, per-user fees, or minimum balance fees on its core banking and card products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$How much cash back do Rho corporate cards offer?$q$, $q$Rho corporate cards can earn up to 1.5% cash back on spend, with no annual or per-card fees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$What is Rho Treasury?$q$, $q$Rho Treasury is an SEC-registered investment advisory service that offers higher-yield cash management, charging a tiered annual management fee based on deposit size.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$How much FDIC insurance does Rho provide?$q$, $q$Through its sweep network via Rho Treasury, Rho can extend FDIC insurance coverage on deposits up to $75 million.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Who founded Rho?$q$, $q$Rho was founded in 2018 by Everett Cook, Alex Wheldon, and Damian Kimmelman.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$How much funding has Rho raised?$q$, $q$Rho has raised approximately $235 million across multiple funding rounds, including a $75 million Series B in 2021.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Does Rho support international payments?$q$, $q$Rho charges a 1% fee on foreign currency transfers as part of its cross-border payment capabilities.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Venture-backed startups managing runway$q$, $q$Startups use Rho's fee-free checking and corporate cards to manage day-to-day spend and preserve cash runway.$q$, $q$Early and growth-stage venture-backed startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Scale-ups automating AP and expense workflows$q$, $q$Growing companies consolidate bill pay, expense management, and approval workflows on one platform.$q$, $q$Scale-up finance and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Companies seeking higher FDIC coverage on cash$q$, $q$Businesses with larger cash balances use Rho Treasury for higher-yield management and expanded FDIC sweep coverage.$q$, $q$Finance teams managing significant cash reserves$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Rho Business (Core Banking and Cards)$q$, $q$$0/month$q$, $q$n/a (no subscription fee)$q$, NULL, $q$["Business checking account with no fees","Corporate credit cards with no annual or per-card fees","Up to 1.5% cash back on card spend","No ACH or wire transfer fees","Accounts payable automation","Expense management with approval workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$Rho Treasury$q$, $q$Tiered management fee: approximately 0.15% annually for deposits of $20M+ up to approximately 0.6% for deposits under $2M$q$, $q$annual (asset-based fee)$q$, NULL, $q$["SEC-registered investment advisory service","FDIC sweep insurance coverage up to $75 million","Access to higher-yield cash management and money market options"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rho was founded in 2018 by Everett Cook, Alex Wheldon, and Damian Kimmelman and is headquartered in New York City. The company has raised roughly $235 million in funding, including a $75 million Series B round in 2021, and employs around 334 people as of 2026. Rho builds a combined banking, corporate card, and treasury management platform aimed at startups and scale-up companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rho offers no-fee business checking accounts, corporate cards with up to 1.5% cash back and no annual fees, accounts payable automation, and expense management with customizable approval workflows. Rho Treasury adds access to higher-yield cash management and a sweep network offering FDIC insurance coverage up to $75 million, operated under Rho's status as an SEC-registered investment advisor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('04370e5b-5bb7-44db-b5e6-2db98849560d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Rho does not charge monthly subscription fees, per-user fees, minimum balance fees, or fees for same-day ACH, wires, or checks on its core banking and card products. The exception is Rho Treasury, which charges an annual, tiered management fee ranging from about 0.15% for larger balances of $20 million or more up to about 0.6% for balances under $2 million.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Unified Multi-VCS Support$q$, $q$Manage Git, Mercurial, and Subversion repositories from a single centralized platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Fine-Grained Permissions$q$, $q$Repository, branch, and path-level access control for compliance and governance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Built-In Code Review$q$, $q$Inline commenting, reviewer assignment, and code chat for instant code reviews.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Full-Text Code Search$q$, $q$Indexes and searches source code across all repositories.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Enterprise Authentication$q$, $q$Supports LDAP, Active Directory, SAML, CAS, Google, OAuth, and two-factor authentication.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Third-Party Integrations$q$, $q$Predefined integrations with JIRA, Jenkins, Bamboo, and Slack.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$High Availability Architecture$q$, $q$Multi-node deployment configurations for Enterprise Edition customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$On-Premises or Managed Cloud Deployment$q$, $q$Self-host with Community or Enterprise Edition, or use RhodeCode's managed Cloud hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Supports three major version control systems in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Free, unlimited-user Community Edition available$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Strong permission and compliance controls suited to regulated industries$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$On-premises deployment option for data sovereignty requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Over a decade of product development and enterprise use$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Managed Cloud hosting option available for teams that don't want to self-host$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Enterprise and Cloud editions both require a 10-user minimum purchase$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Smaller ecosystem and community than GitHub or GitLab$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Admin interface feels dated compared to newer DevOps platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Less cost-competitive for very small teams under 10 users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Fewer built-in CI/CD features than all-in-one DevOps platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Company employee count and scale are not publicly disclosed, making due diligence harder$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Is RhodeCode free?$q$, $q$The Community Edition is free and open source with unlimited users and repositories; Enterprise and Cloud editions are paid.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$What version control systems does RhodeCode support?$q$, $q$RhodeCode supports Git, Mercurial, and Subversion repositories within a single unified platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$What's the difference between RhodeCode Enterprise and Cloud editions?$q$, $q$Enterprise is a self-hosted, per-user-per-year license at $75/user/year, while Cloud is a managed hosting subscription starting at $8/user/month with all Enterprise features included.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Is there a minimum number of users for paid plans?$q$, $q$Yes, both Enterprise Edition and Cloud require a minimum of 10 users.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Who founded RhodeCode?$q$, $q$RhodeCode was started in 2010 by Marcin Kuzminski, with the company formally incorporated in 2013 alongside co-founder Sebastian Kreutzberger.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Can RhodeCode be self-hosted?$q$, $q$Yes, both the Community and Enterprise editions can be deployed entirely on-premises.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Does RhodeCode integrate with JIRA?$q$, $q$Yes, RhodeCode Enterprise includes predefined integrations with JIRA, Jenkins, Bamboo, and Slack.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Does RhodeCode support two-factor authentication?$q$, $q$Yes, two-factor authentication is available as part of RhodeCode Enterprise's unified authentication options.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Enterprises consolidating multiple version control systems$q$, $q$Organizations running a mix of Git, Mercurial, and SVN repositories use RhodeCode to manage them all under one system.$q$, $q$Large enterprises with mixed VCS environments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Regulated industries needing on-premises source control$q$, $q$Companies with strict compliance requirements deploy RhodeCode on-premises for fine-grained permissions and data control.$q$, $q$Regulated industries such as finance and healthcare$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$DevOps teams wanting unified code review across VCS backends$q$, $q$DevOps and platform teams standardize code review and integrations across projects regardless of underlying VCS.$q$, $q$DevOps and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Community Edition$q$, $q$Free$q$, $q$n/a (free, open source)$q$, NULL, $q$["Unlimited users and repositories","Git, Mercurial, and Subversion support","On-premises deployment","Basic LDAP/Active Directory authentication","Code review tools","Full-text search","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Enterprise Edition$q$, $q$$75 per user/year (10-user minimum)$q$, $q$annual$q$, NULL, $q$["Technical support with SLA","Instant code reviews with built-in code chat","Scalable code search across all repositories","High availability with multi-node configurations","Integrations with JIRA, Jenkins, Bamboo, and Slack","Unified enterprise authentication (LDAP, SAML, AD, CAS, Google, OAuth, 2FA)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$Cloud$q$, $q$From $8 per user/month (10-user minimum)$q$, $q$monthly$q$, NULL, $q$["All Enterprise Edition features","Dedicated domain with enterprise-grade SSL","Unlimited traffic, disk space, and repository size","Dedicated isolated hardware","Geo-located instances (US, Asia, Europe)","Daily backups and performance monitoring"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RhodeCode originated in 2010 under founder Marcin Kuzminski and was formally incorporated in 2013 with co-founder Sebastian Kreutzberger. The company is headquartered in Berlin, Germany, with an additional office in Palo Alto, California, and remains a small, privately held business. Its product targets software developers, project managers, and DevOps engineers who need centralized control over Git, Mercurial, and Subversion repositories within a single organization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RhodeCode's standout capability is unifying three version control systems under one authentication, permission, and code review layer, rather than supporting only Git. Enterprise customers get instant code reviews with built-in chat, scalable cross-repository search, high-availability multi-node deployment, and integrations with tools like JIRA, Jenkins, Bamboo, and Slack, along with enterprise authentication options including SAML, LDAP, CAS, OAuth, and two-factor authentication.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85550e75-0afc-4140-81a3-4e711ba76ca4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RhodeCode Community Edition is free and open source with unlimited users and repositories for self-hosted, on-premises deployment. RhodeCode Enterprise Edition costs $75 per user per year with a 10-user minimum, while the newer RhodeCode Cloud offering starts at $8 per user per month, also with a 10-user minimum, providing managed hosting with all Enterprise features included.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Unified Inbox$q$, $q$Centralizes email, live chat, social media, SMS, and phone conversations in one dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$AI Customer Service Agent$q$, $q$An add-on AI agent that automates responses and resolves tickets without human agents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Self-Service Portal$q$, $q$Lets customers manage their own orders, returns, and exchanges.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Automation Rules$q$, $q$Workflow automation for ticket routing and repetitive support tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Multi-Brand and Multi-Language Support$q$, $q$Manage multiple storefronts and languages from one account on Pro Max and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Advanced Reporting$q$, $q$Revenue-impact, CSAT, and satisfaction analytics available on higher tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Ecommerce Integrations$q$, $q$Native integration with Shopify and other online store platforms.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$White-Glove Migration$q$, $q$Assisted onboarding and migration from other helpdesk tools included on all plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Purpose-built for e-commerce rather than general-purpose support$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$AI automation included even on the entry Pro plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Self-service order and returns portal reduces incoming ticket volume$q$, 2);
