INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$SMS and phone channels are reserved for the higher Pro Max tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Enterprise pricing is not published and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Standalone AI agent add-on costs $500/month on top of seat fees$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Less suited to non-ecommerce industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Smaller integration marketplace than larger, more established helpdesk platforms$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$What does Richpanel cost per agent?$q$, $q$The Pro plan is $59 per agent per month billed annually, and Pro Max is $89 per agent per month billed annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Is Richpanel only for e-commerce?$q$, $q$Yes, Richpanel is built specifically for e-commerce and direct-to-consumer brands rather than general businesses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$What is the Richpanel AI agent add-on?$q$, $q$It is a standalone AI customer service agent priced at $500 per month plus $100 per seat for the helpdesk the team works in.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Does Richpanel integrate with Shopify?$q$, $q$Yes, Richpanel offers native integration with Shopify and other e-commerce platforms.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$What's included in the self-service portal?$q$, $q$The self-service portal add-on includes order management, returns processing, a branded help center, and custom automation flows, priced roughly $99-$500/month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$How many seats come with the Pro plan?$q$, $q$The Pro plan includes up to 3 seats.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Does Richpanel offer a savings guarantee?$q$, $q$Richpanel advertises a guaranteed 30% savings versus Zendesk or Gorgias plus a 30% reduction in tickets within 60 days, or a refund.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Is there a minimum agent count for Enterprise?$q$, $q$Yes, the Enterprise plan requires a minimum of 10 agents and is custom priced.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Shopify and e-commerce brands consolidating support channels$q$, $q$Online retailers unify email, chat, and social support into one inbox to streamline agent workflows.$q$, $q$Shopify and other e-commerce merchants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$DTC companies automating order and returns inquiries$q$, $q$Direct-to-consumer brands use the self-service portal and AI agent to reduce repetitive order and return tickets.$q$, $q$Direct-to-consumer (DTC) brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Growing online retailers needing multi-brand support$q$, $q$Retailers operating multiple storefronts or languages manage them from a single Richpanel account on Pro Max and above.$q$, $q$Multi-brand e-commerce operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Pro$q$, $q$$59/agent/month ($708/year)$q$, $q$annual$q$, NULL, $q$["Up to 3 seats included","Email, live chat, and social channels","Basic reporting and automation rules","AI features included at no extra cost"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Pro Max$q$, $q$$89/agent/month ($1,068/year)$q$, $q$annual$q$, NULL, $q$["SMS and phone support","Unlimited automations and campaigns","Multiple brands and languages","Advanced reporting including revenue and CSAT"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Minimum of 10 agents","White-glove setup and concierge onboarding","Campaign manager and advanced features","Custom integrations and ticket analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$AI Agent Add-On$q$, $q$$500/month plus $100/seat$q$, $q$monthly$q$, NULL, $q$["Dedicated AI customer service agent","Helpdesk seat included for human agents","Works alongside existing Richpanel plans"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Richpanel was founded in 2019 and is headquartered in San Jose, California. The company builds AI-powered customer service software built exclusively for e-commerce and direct-to-consumer brands, combining a unified support inbox, AI automation, and customer self-service tools into a single platform aimed at reducing support ticket volume for online retailers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Richpanel centralizes email, live chat, social media, SMS, and phone channels into one inbox, layers in AI-driven automation and an optional AI support agent, and gives customers a self-service portal to manage orders and returns without contacting an agent. Higher tiers add multi-brand and multi-language support along with revenue-impact and CSAT reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f232ed0f-8c1a-4fee-9d5d-b7fe5094bbbb', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Richpanel's help desk is sold as Pro at $59/agent/month (billed annually), Pro Max at $89/agent/month (billed annually), and a custom-priced Enterprise tier requiring at least 10 agents. A standalone AI agent add-on costs $500/month plus $100 per seat, and a self-service portal add-on runs roughly $99 to $500/month depending on scale.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Cloud Business Phone$q$, $q$Hosted PBX with unlimited calling within the US and Canada.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Team Messaging$q$, $q$Persistent chat, file sharing, and task management for teams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Video Meetings$q$, $q$Built-in video conferencing supporting up to 100-200 participants depending on plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Auto-Attendant and Call Queues$q$, $q$Automated call routing and queue management for business phone lines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$SMS/MMS Messaging$q$, $q$Business texting with a monthly per-user message allowance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$AI-Powered Features$q$, $q$AI call summaries, transcription, and assistant tools branded as RingCentral AI.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Contact Center Add-On$q$, $q$Omnichannel customer service tools available as a separate paid add-on.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Extensive App Integrations$q$, $q$Connects with 300+ third-party apps including Microsoft 365, Google Workspace, and Salesforce.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Mature, reliable UCaaS platform with over two decades of development$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Combines phone, video, and messaging in one integrated app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Deep third-party integrations with major business software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Scales from small businesses to large enterprises$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Meaningful discounts available with annual billing$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$AI features included across plan tiers$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Automatic call recording is not included on the entry Core plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Actual invoices often run 20-35% higher than list pricing due to fees and taxes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Contact Center requires a separate add-on purchase$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Per-user pricing model can get costly for larger teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Some advanced features are reserved for the top Ultra tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Setup and onboarding can be complex for larger deployments$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$What is RingCentral RingEX?$q$, $q$RingEX is RingCentral's core unified communications platform, formerly branded RingCentral MVP, combining phone, video, and messaging.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$How much does RingCentral cost per user?$q$, $q$Pricing ranges from about $20 to $35 per user per month with annual billing, or $30 to $45 per user per month billed monthly, across the Core, Advanced, and Ultra tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$What's the difference between Core, Advanced, and Ultra?$q$, $q$Each tier adds features and higher usage limits, with Advanced adding automatic call recording and Ultra adding larger video meetings, unlimited storage, and device analytics.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Does RingCentral include video meetings?$q$, $q$Yes, video meetings for up to 100 participants are included on Core, rising to 200 participants on the Ultra tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Is there a contact center option?$q$, $q$Yes, RingCentral Contact Center is available as a separate add-on to any RingEX plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$How many participants can join a RingCentral video meeting?$q$, $q$Depending on the plan, RingCentral video meetings support up to 100 or up to 200 participants.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Is RingCentral publicly traded?$q$, $q$Yes, RingCentral, Inc. trades on the NYSE under the ticker symbol RNG.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$What integrations does RingCentral support?$q$, $q$RingCentral integrates with more than 300 third-party applications, including Microsoft 365, Google Workspace, and Salesforce.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Distributed and hybrid teams needing unified communications$q$, $q$Teams use RingEX to combine phone, messaging, and video into one platform for remote and hybrid work.$q$, $q$Distributed and hybrid workforces$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Call centers needing scalable contact center tools$q$, $q$Customer service teams add RingCentral Contact Center for omnichannel support on top of the core phone platform.$q$, $q$Customer support and call center teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Enterprises consolidating communication vendors$q$, $q$Large organizations replace multiple point solutions for phone, video, and messaging with a single RingCentral platform.$q$, $q$Mid-market and enterprise IT and communications teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Core$q$, $q$$20/user/month billed annually ($30/user/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited US and Canada calling","Voicemail-to-text","Call queues and auto-attendant","Video meetings for up to 100 participants","25 SMS messages per user per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Advanced$q$, $q$$25/user/month billed annually ($35/user/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Core","Automatic call recording","Higher usage limits","Additional integrations and call handling features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$Ultra$q$, $q$$35/user/month billed annually ($45/user/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Advanced","Unlimited storage","Device analytics","Video meetings for up to 200 participants"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RingCentral, Inc. was founded in 1999 and is headquartered in Belmont, California. It is a publicly traded company on the NYSE under the ticker RNG, with trailing twelve-month revenue of roughly $2.5 billion and an employee base reported between roughly 4,260 and over 7,000 people depending on the source. The company has grown into one of the major providers of cloud-based unified communications for businesses of all sizes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RingCentral's core RingEX platform (formerly branded RingCentral MVP) combines a cloud business phone system, team messaging, video meetings, and SMS texting in one subscription. It includes call queues, an auto-attendant, and AI-powered features such as call summaries and transcription, plus integrations with over 300 third-party apps including Microsoft 365, Google Workspace, and Salesforce. A separate Contact Center product extends the platform for customer service teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92a082b4-89b7-491c-a783-39088d0397e1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RingEX is priced per user per month across three tiers: Core, Advanced, and Ultra. Annual billing brings the price down to $20, $25, and $35 per user per month respectively, versus $30, $35, and $45 per user per month for monthly billing. Contact Center is sold separately as an add-on, and actual invoices often exceed list pricing once fees, extra numbers, and usage overages are included.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Free Video Pro Plan$q$, $q$Unlimited meetings for up to 100 participants with a 50-minute time limit per meeting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Video Pro+ Plan$q$, $q$Extends meetings to up to 24 hours and up to 200 participants for $10/user/month billed annually.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Screen Sharing and Chat$q$, $q$Built-in collaboration tools available during meetings on both free and paid tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Cloud Recording$q$, $q$Available on Video Pro+ for saving and sharing meeting recordings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$End-to-End Encryption$q$, $q$Available on Video Pro+ for teams with heightened security requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$AI Meeting Tools$q$, $q$AI-generated meeting notes, transcription, and summaries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Calendar Integrations$q$, $q$Syncs with Google Calendar, Outlook, and other scheduling tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Bundled with RingEX$q$, $q$RingEX phone plan subscribers receive expanded video meeting capacity included in their subscription.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Generous free tier compared to many video conferencing competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Simple two-tier pricing structure (free and Pro+)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Large participant capacity of up to 200 on the paid tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$End-to-end encryption available for security-conscious teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Tightly integrated with RingCentral's broader communications suite$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$AI-generated meeting summaries included$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Free tier capped at 50 minutes per meeting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Standalone video pricing is less prominently published than RingEX bundle pricing and may require checking a dedicated page$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Fewer dedicated webinar features compared to specialized webinar platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Most value is realized when combined with a full RingEX phone subscription rather than purchased standalone$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Lower storage limits apply on the free tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Overlapping branding with RingCentral's broader video meeting bundle can create confusion about which plan includes which features$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Is RingCentral Video free?$q$, $q$Yes, the Video Pro tier is free and supports unlimited meetings for up to 100 participants, capped at 50 minutes per meeting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$How many people can join a free RingCentral Video meeting?$q$, $q$The free Video Pro plan supports up to 100 participants per meeting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$What is the time limit on free meetings?$q$, $q$Free Video Pro meetings are limited to 50 minutes each.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$How much does RingCentral Video Pro+ cost?$q$, $q$Video Pro+ costs $10 per user per month when billed annually.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Does RingCentral Video support end-to-end encryption?$q$, $q$Yes, end-to-end encryption is available on the paid Video Pro+ plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Is RingCentral Video the same as RingCentral Meetings?$q$, $q$RingCentral Video is the current branding for what was formerly called RingCentral Meetings.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Can I use RingCentral Video without a phone plan?$q$, $q$Yes, RingCentral Video Pro and Pro+ can both be used as standalone video products without a full RingEX phone subscription.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Does RingCentral Video integrate with calendars?$q$, $q$Yes, it integrates with calendar tools such as Google Calendar and Outlook for scheduling meetings.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Small teams and freelancers needing free video calls$q$, $q$Small teams use the free Video Pro plan for quick meetings without a subscription cost.$q$, $q$Freelancers and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Growing businesses needing longer, larger meetings$q$, $q$Businesses upgrade to Video Pro+ for meetings beyond 50 minutes, larger participant counts, and recording.$q$, $q$Growing businesses and larger teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$RingEX customers wanting expanded video capacity$q$, $q$Existing RingEX phone plan customers use the video capacity bundled into their subscription rather than buying a separate video plan.$q$, $q$Existing RingEX/RingCentral phone customers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Video Pro (Free)$q$, $q$$0/month$q$, $q$n/a (free)$q$, NULL, $q$["Unlimited meetings","Up to 100 participants per meeting","50-minute time limit per meeting","Screen sharing and chat"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$Video Pro+$q$, $q$$10/user/month billed annually$q$, $q$annual$q$, NULL, $q$["Up to 200 participants per meeting","Meetings up to 24 hours long","Cloud recording","End-to-end encryption","Expanded cloud storage"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RingCentral Video is the video conferencing product of RingCentral, Inc., the publicly traded communications company founded in 1999 and headquartered in Belmont, California. Formerly branded RingCentral Meetings, the product is sold both as a standalone freemium offering and bundled into RingCentral's broader RingEX phone and messaging plans, giving customers flexibility between a video-only subscription and a full communications platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free Video Pro tier supports unlimited meetings for up to 100 participants with a 50-minute per-meeting limit, along with screen sharing and chat. The paid Video Pro+ tier removes the time cap, extends meeting length to up to 24 hours, raises participant capacity to 200, and adds cloud recording, end-to-end encryption, and expanded storage, alongside AI-powered meeting notes and calendar integrations available across tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88db22aa-79b8-45ed-b2f4-437c05395830', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RingCentral Video Pro is free with no per-user cost, supporting meetings up to 100 participants and 50 minutes long. Video Pro+ costs $10 per user per month billed annually and expands capacity to 200 participants and 24-hour meetings. Customers on a paid RingEX phone plan also receive expanded video meeting capacity of up to 200 participants bundled into their subscription.$q$]::text[], 2);
